import{_ as e,c as o,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Управление квотами: Защита квот и разогрев | Antigravity-Manager","description":"Изучите механизм управления квотами Antigravity-Manager. Используйте Quota Protection для защиты моделей по порогам, Smart Warmup для автоматического разогрева, поддерживайте плановое сканирование и контроль охлаждения.","frontmatter":{"title":"Управление квотами: Защита квот и разогрев | Antigravity-Manager","subtitle":"Управление квотами: Защита квот и разогрев | Antigravity-Manager","sidebarTitle":"Защитите свои квоты моделей","description":"Изучите механизм управления квотами Antigravity-Manager. Используйте Quota Protection для защиты моделей по порогам, Smart Warmup для автоматического разогрева, поддерживайте плановое сканирование и контроль охлаждения.","tags":["quota","warmup","учётные записи","proxy"],"prerequisite":["start-add-account","start-proxy-and-first-client"],"order":5},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/advanced/quota/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/advanced/quota/index.md"}'),d={name:"ru/lbjlaq/Antigravity-Manager/advanced/quota/index.md"};function c(n,t,i,l,s,u){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="управление-квотами-комбинация-quota-protection-smart-warmup" tabindex="-1">Управление квотами: Комбинация Quota Protection + Smart Warmup <a class="header-anchor" href="#управление-квотами-комбинация-quota-protection-smart-warmup" aria-label="Permalink to &quot;Управление квотами: Комбинация Quota Protection + Smart Warmup&quot;">​</a></h1><p>Вы уже довольно стабильно используете Antigravity Tools в качестве прокси, но больше всего боитесь一件事: квота ключевой модели незаметно «съедена», и когда вам реально нужно её использовать, вы обнаруживаете, что она уже настолько низка, что запрос невозможен.</p><p>В этом уроке подробно рассказывается об <strong>управлении квотами</strong>: используйте Quota Protection, чтобы сохранить ключевые модели; используйте Smart Warmup, чтобы выполнить «лёгкий разогрев» когда квота вернётся к полному объёму, снизив временные перебои.</p><h2 id="что-такое-управление-квотами" tabindex="-1">Что такое управление квотами? <a class="header-anchor" href="#что-такое-управление-квотами" aria-label="Permalink to &quot;Что такое управление квотами?&quot;">​</a></h2><p><strong>Управление квотами</strong> означает использование двух связных механизмов в Antigravity Tools для контроля «как тратятся квоты»: когда процент остаточной квоты определённой модели падает ниже порога, Quota Protection добавит эту модель в <code>protected_models</code> учётной записи, при запросе этой модели она будет избегаться с приоритетом; когда квота вернётся к 100%, Smart Warmup запустит запрос разогрева с минимальным трафиком и использует локальный исторический файл для 4-часового охлаждения.</p><h2 id="что-вы-сможете-сделать-после-изучения" tabindex="-1">Что вы сможете сделать после изучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-изучения" aria-label="Permalink to &quot;Что вы сможете сделать после изучения&quot;">​</a></h2><ul><li>Включить Quota Protection, чтобы учётные записи с низкой квотой автоматически «уступали дорогу», сохраняя высокоценные модели для ключевых запросов</li><li>Включить Smart Warmup, чтобы автоматически разогревать, когда квота вернётся к полному (и знать, как 4-часовое охлаждение влияет на частоту срабатывания)</li><li>Понять, какие поля <code>quota_protection</code> / <code>scheduled_warmup</code> / <code>protected_models</code> вступают в силу где</li><li>Знать, какие имена моделей будут нормализованы в «группу защиты» (а какие не)</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><ul><li>Вы считаете, что выполняете «ротацию учётных записей», но на самом деле постоянно потребляете один и тот же класс высокоценных моделей</li><li>Квота стала низкой, только когда вы обнаруживаете, что даже warmup клиентов вроде Claude Code потратил лимит</li><li>Вы включили разогрев, но не знаете, когда именно он срабатывает, есть ли охлаждение, повлияет ли это на квоту</li></ul><h2 id="когда-использовать-этот-подход" tabindex="-1">Когда использовать этот подход <a class="header-anchor" href="#когда-использовать-этот-подход" aria-label="Permalink to &quot;Когда использовать этот подход&quot;">​</a></h2><ul><li>У вас есть несколько пулов учётных записей, и вы хотите, чтобы ключевые модели в «важный момент» ещё имели запас</li><li>Вы не хотите вручную следить за временем возврата квоты к полному, хотите, чтобы система автоматически выполняла «проверку после возврата к полному»</li></ul><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Предварительные требования</p><p>В этом уроке подразумевается, что вы уже умеете:</p><ul><li>На странице <strong>Accounts</strong> видеть список учётных записей и вручную обновлять квоту</li><li>Уже запускали локальный обратный прокси (минимум доходит до <code>/healthz</code>)</li></ul></div><p>Кроме того, Smart Warmup будет записывать локальный исторический файл <code>warmup_history.json</code>. Он находится в каталоге данных, как найти каталог данных и как выполнять резервное копирование, можно сначала посмотреть <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/start/first-run-data/">Первый запуск: Каталог данных, журналы, трей и автозапуск</a></strong>.</p><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Эта «комбинированная стратегия» по сути очень проста:</p><ul><li>Quota Protection отвечает за «прекратить трату»: когда модель ниже порога, она помечается как защищённая, при запросе этой модели она избегается с приоритетом (на уровне модели, а не универсальное отключение учётной записи).</li><li>Smart Warmup отвечает за «проверить после возврата к полному»: когда модель возвращается к 100%, запускается запрос разогрева с минимальным трафиком, подтверждая доступность цепочки, и используется 4-часовое охлаждение, чтобы избежать повторных помех.</li></ul><p>Им соответствуют поля конфигурации в <code>AppConfig</code> на стороне фронтенда:</p><ul><li><code>quota_protection.enabled / threshold_percentage / monitored_models</code> (см. <code>src/types/config.ts</code>)</li><li><code>scheduled_warmup.enabled / monitored_models</code> (см. <code>src/types/config.ts</code>)</li></ul><p>А логика, действительно определяющая «при запросе этой модели нужно ли пропустить эту учётную запись», находится на стороне бэкенда в TokenManager:</p><ul><li>Поле <code>protected_models</code> в файле учётной записи будет участвовать в фильтрации в <code>get_token(..., target_model)</code> (см. <code>src-tauri/src/proxy/token_manager.rs</code>)</li><li><code>target_model</code> будет сначала нормализован (<code>normalize_to_standard_id</code>), поэтому варианты вроде <code>claude-sonnet-4-5-thinking</code> будут свёрнуты в одну и ту же «группу защиты» (см. <code>src-tauri/src/proxy/common/model_mapping.rs</code>)</li></ul><h2 id="следуите-за-мнои" tabindex="-1">Следуйте за мной <a class="header-anchor" href="#следуите-за-мнои" aria-label="Permalink to &quot;Следуйте за мной&quot;">​</a></h2><h3 id="шаг-1-сначала-приведите-квоту-в-«понятное-состояние»" tabindex="-1">Шаг 1: Сначала приведите квоту в «понятное состояние» <a class="header-anchor" href="#шаг-1-сначала-приведите-квоту-в-«понятное-состояние»" aria-label="Permalink to &quot;Шаг 1: Сначала приведите квоту в «понятное состояние»&quot;">​</a></h3><p><strong>Почему</strong> Quota Protection основывается на <code>quota.models[].percentage</code> учётной записи. Если вы не получили квоту, логика защиты не может сработать на вас.</p><p>Путь действий: откройте страницу <strong>Accounts</strong>, нажмите кнопку обновления на панели инструментов (отдельная учётная запись или массово).</p><p><strong>Вы должны увидеть</strong>: в строках учётных записей появляются проценты квоты по моделям (например, 0-100) и reset time.</p><h3 id="шаг-2-включите-smart-warmup-в-settings-необязательно-но-рекомендуется" tabindex="-1">Шаг 2: Включите Smart Warmup в Settings (необязательно, но рекомендуется) <a class="header-anchor" href="#шаг-2-включите-smart-warmup-в-settings-необязательно-но-рекомендуется" aria-label="Permalink to &quot;Шаг 2: Включите Smart Warmup в Settings (необязательно, но рекомендуется)&quot;">​</a></h3><p><strong>Почему</strong> Цель Smart Warmup не «экономить квоту», а «проверить цепочку после возврата квоты к полному». Он срабатывает только когда квота модели достигает 100%, и есть 4-часовое охлаждение.</p><p>Путь действий: перейдите в <strong>Settings</strong>, перейдите в область настроек учётных записей, включите переключатель <strong>Smart Warmup</strong>, затем выберите модели, которые хотите мониторить.</p><p>Не забудьте сохранить настройки.</p><p><strong>Вы должны увидеть</strong>: после развертывания Smart Warmup появляется список моделей; сохраняется минимум 1 отмеченная модель.</p><h3 id="шаг-3-включите-quota-protection-и-установите-порог-и-модели-мониторинга" tabindex="-1">Шаг 3: Включите Quota Protection и установите порог и модели мониторинга <a class="header-anchor" href="#шаг-3-включите-quota-protection-и-установите-порог-и-модели-мониторинга" aria-label="Permalink to &quot;Шаг 3: Включите Quota Protection и установите порог и модели мониторинга&quot;">​</a></h3><p><strong>Почему</strong> Quota Protection — это ядро «сохранения запасов»: когда процент квоты отслеживаемых моделей <code>&lt;= threshold_percentage</code>, эта модель будет записана в <code>protected_models</code> файла учётной записи, при последующих запросах этой модели будут с приоритетом пропущены这类 учётные записи.</p><p>Путь действий: в <strong>Settings</strong> включите переключатель <strong>Quota Protection</strong>.</p><ol><li>Установите порог (<code>1-99</code>)</li><li>Отметьте модели, которые хотите мониторить (минимум 1)</li></ol><div class="tip custom-block"><p class="custom-block-title">Очень удобная начальная конфигурация</p><p>Если вы не хотите ломать голову, начните с <code>threshold_percentage=10</code> по умолчанию (см. <code>src/pages/Settings.tsx</code>).</p></div><p><strong>Вы должны увидеть</strong>: в отмеченных моделях Quota Protection сохраняется минимум 1 (UI не позволит вам отменить последнюю).</p><h3 id="шаг-4-подтвердите-«нормализацию-группы-защиты»-не-приведет-вас-к-ловушке" tabindex="-1">Шаг 4: Подтвердите «нормализацию группы защиты» не приведёт вас к ловушке <a class="header-anchor" href="#шаг-4-подтвердите-«нормализацию-группы-защиты»-не-приведет-вас-к-ловушке" aria-label="Permalink to &quot;Шаг 4: Подтвердите «нормализацию группы защиты» не приведёт вас к ловушке&quot;">​</a></h3><p><strong>Почему</strong> Когда TokenManager принимает решение о защите квоты, он сначала нормализует <code>target_model</code> в стандартный ID (<code>normalize_to_standard_id</code>). Например, <code>claude-sonnet-4-5-thinking</code> будет нормализован в <code>claude-sonnet-4-5</code>.</p><p>Это означает:</p><ul><li>Вы отмечаете <code>claude-sonnet-4-5</code> в Quota Protection</li><li>Когда вы фактически запрашиваете <code>claude-sonnet-4-5-thinking</code></li></ul><p>Всё ещё будет срабатывать защита (потому что они принадлежат одной группе).</p><p><strong>Вы должны увидеть</strong>: когда <code>protected_models</code> какой-либо учётной записи содержит <code>claude-sonnet-4-5</code>, запросы к <code>claude-sonnet-4-5-thinking</code> будут с приоритетом пропускать эту учётную запись.</p><h3 id="шаг-5-при-необходимости-немедленнои-проверки-используите-«ручнои-разогрев»" tabindex="-1">Шаг 5: При необходимости немедленной проверки используйте «ручной разогрев» <a class="header-anchor" href="#шаг-5-при-необходимости-немедленнои-проверки-используите-«ручнои-разогрев»" aria-label="Permalink to &quot;Шаг 5: При необходимости немедленной проверки используйте «ручной разогрев»&quot;">​</a></h3><p><strong>Почему</strong> Периодическое сканирование Smart Warmup — раз в 10 минут (см. <code>src-tauri/src/modules/scheduler.rs</code>). Если вы хотите немедленно проверить доступность цепочки, ручной разогрев более прямой.</p><p>Путь действий: откройте страницу <strong>Accounts</strong>, нажмите кнопку «Разогреть» на панели инструментов:</p><ul><li>Не выбирайте учётную запись: запускается массовый разогрев (вызывается <code>warm_up_all_accounts</code>)</li><li>Выберите учётную запись: по очереди запускается разогрев для выбранных учётных записей (вызывается <code>warm_up_account</code>)</li></ul><p><strong>Вы должны увидеть</strong>: появляется toast, содержимое из строки, возвращаемой бэкендом (например, &quot;Warmup task triggered ...&quot;).</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><ul><li>Вы можете видеть процент квоты по моделям на странице Accounts (доказывая, что цепочка данных квоты OK)</li><li>Вы можете включить Quota Protection / Smart Warmup в Settings и успешно сохранить конфигурацию</li><li>Вы понимаете, что <code>protected_models</code> — это «ограничение на уровне модели»: одна учётная запись может быть пропущена только для определённых моделей</li><li>Вы знаете, что у разогрева есть 4-часовое охлаждение: повторное нажатие разогрева в короткое время может увидеть подсказки о «skipped/cooldown»</li></ul><h2 id="напоминания-о-возможных-ошибках" tabindex="-1">Напоминания о возможных ошибках <a class="header-anchor" href="#напоминания-о-возможных-ошибках" aria-label="Permalink to &quot;Напоминания о возможных ошибках&quot;">​</a></h2><h3 id="_1-вы-включили-quota-protection-но-она-все-еще-не-срабатывает" tabindex="-1">1) Вы включили Quota Protection, но она всё ещё не срабатывает <a class="header-anchor" href="#_1-вы-включили-quota-protection-но-она-все-еще-не-срабатывает" aria-label="Permalink to &quot;1) Вы включили Quota Protection, но она всё ещё не срабатывает&quot;">​</a></h3><p>Самая частая причина: у учётной записи нет данных <code>quota</code>. Логика защиты на стороне бэкенда должна сначала прочитать <code>quota.models[]</code>, чтобы судить о пороге (см. <code>src-tauri/src/proxy/token_manager.rs</code>).</p><p>Вы можете вернуться к <strong>Шагу 1</strong>, сначала получить квоту.</p><h3 id="_2-почему-только-несколько-моделеи-будут-считаться-«группои-защиты»" tabindex="-1">2) Почему только несколько моделей будут считаться «группой защиты»? <a class="header-anchor" href="#_2-почему-только-несколько-моделеи-будут-считаться-«группои-защиты»" aria-label="Permalink to &quot;2) Почему только несколько моделей будут считаться «группой защиты»?&quot;">​</a></h3><p>Нормализация <code>target_model</code> в TokenManager — это «белый список»: только явно перечисленные имена моделей будут сопоставлены со стандартным ID (см. <code>src-tauri/src/proxy/common/model_mapping.rs</code>).</p><p>Логика после нормализации: использовать нормализованное имя (стандартный ID или исходное имя модели) для сопоставления с полем <code>protected_models</code> учётной записи. Если совпадение успешно, эта учётная запись будет пропущена (см. <code>src-tauri/src/proxy/token_manager.rs:555-560, 716-719</code>). Это означает:</p><ul><li>Модели в белом списке (например, <code>claude-sonnet-4-5-thinking</code>) будут нормализованы в стандартный ID (<code>claude-sonnet-4-5</code>), затем проверяться, есть ли они в <code>protected_models</code></li><li>Модели вне белого списка при неудачной нормализации возвращаются к исходному имени модели, всё ещё будут сопоставляться с <code>protected_models</code></li></ul><p>Другими словами, решение о защите квоты действительно действует на «все имена моделей», только модели в белом списке будут сначала нормализованы.</p><h3 id="_3-почему-ручнои-плановыи-разогрев-требует-чтобы-прокси-был-запущен" tabindex="-1">3) Почему ручной/плановый разогрев требует, чтобы прокси был запущен? <a class="header-anchor" href="#_3-почему-ручнои-плановыи-разогрев-требует-чтобы-прокси-был-запущен" aria-label="Permalink to &quot;3) Почему ручной/плановый разогрев требует, чтобы прокси был запущен?&quot;">​</a></h3><p>Запросы разогрева в конечном итоге попадут на внутреннюю конечную точку локального прокси: <code>POST /internal/warmup</code> (см. маршрут в <code>src-tauri/src/proxy/server.rs</code>, а также реализацию в <code>src-tauri/src/proxy/handlers/warmup.rs</code>). Если вы не запустили службу прокси, warmup не удастся.</p><p>Кроме того, порт вызываемого разогрева берётся из конфигурации: <code>proxy.port</code> (если чтение конфигурации не удаётся, он вернётся к <code>8045</code> по умолчанию, см. <code>src-tauri/src/modules/quota.rs</code>).</p><h2 id="краткое-содержание-урока" tabindex="-1">Краткое содержание урока <a class="header-anchor" href="#краткое-содержание-урока" aria-label="Permalink to &quot;Краткое содержание урока&quot;">​</a></h2><ul><li>Quota Protection выполняет «стоп-убыток»: при падении ниже порога записать модель в <code>protected_models</code>, при запросе этой модели избегать с приоритетом</li><li>Smart Warmup выполняет «проверку после возврата к полному»: срабатывает только при 100%, сканирование раз в 10 минут, 4-часовое охлаждение</li><li>Оба зависят от цепочки «обновление квоты»: сначала есть <code>quota.models[]</code>, тогда управление имеет основу</li></ul><h2 id="предварительныи-просмотр-следующего-урока" tabindex="-1">Предварительный просмотр следующего урока <a class="header-anchor" href="#предварительныи-просмотр-следующего-урока" aria-label="Permalink to &quot;Предварительный просмотр следующего урока&quot;">​</a></h2><p>Управление квотами решает «как тратить стабильнее». Следующий урок — посмотреть <strong>Proxy Monitor</strong>, превращая вызовы чёрного ящика в воспроизводимую цепочку доказательств.</p><hr><h2 id="приложение-ссылка-на-исходныи-код" tabindex="-1">Приложение: Ссылка на исходный код <a class="header-anchor" href="#приложение-ссылка-на-исходныи-код" aria-label="Permalink to &quot;Приложение: Ссылка на исходный код&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть и просмотреть местоположение исходного кода</strong></summary><blockquote><p>Дата обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>UI Quota Protection (порог, выбор модели, минимум 1)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/QuotaProtection.tsx#L13-L168" target="_blank" rel="noreferrer"><code>src/components/settings/QuotaProtection.tsx</code></a></td><td>13-168</td></tr><tr><td>UI Smart Warmup (включить по умолчанию, минимум 1)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/SmartWarmup.tsx#L14-L120" target="_blank" rel="noreferrer"><code>src/components/settings/SmartWarmup.tsx</code></a></td><td>14-120</td></tr><tr><td>Поля конфигурации управления квотами (<code>quota_protection</code> / <code>scheduled_warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/types/config.ts#L54-L94" target="_blank" rel="noreferrer"><code>src/types/config.ts</code></a></td><td>54-94</td></tr><tr><td>Порог по умолчанию и конфигурация по умолчанию (<code>threshold_percentage: 10</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L20-L51" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>20-51</td></tr><tr><td>Запись/восстановление <code>protected_models</code> (суждение порога и сохранение на диск)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L254-L467" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>254-467</td></tr><tr><td>Фильтрация защиты квоты на стороне запроса (<code>get_token(..., target_model)</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L470-L674" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>470-674</td></tr><tr><td>Нормализация группы защиты (<code>normalize_to_standard_id</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L230-L254" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>230-254</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Команды ручного разогрева (<code>warm_up_all_accounts</code> / <code>warm_up_account</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L167-L212" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>167-212</td></tr><tr><td>Реализация разогрева (вызов внутренней конечной точки <code>/internal/warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/quota.rs#L271-L512" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/quota.rs</code></a></td><td>271-512</td></tr><tr><td>Реализация внутренней конечной точки разогрева (создание запроса + вызов вышестоящего)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/warmup.rs#L3-L220" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/warmup.rs</code></a></td><td>3-220</td></tr></tbody></table></details>',69)])])}const h=e(d,[["render",c]]);export{m as __pageData,h as default};
